// ❌ BAD - business logic living inside the controller action
public IActionResult Checkout(int orderId)
{
    var order = _db.Orders.Find(orderId);
    order.Status = "Shipped";
    order.ShippedAt = DateTime.UtcNow;
    _db.SaveChanges();
    return View(order);
}

// ✅ GOOD - controller delegates to a service (the Model layer)
public IActionResult Checkout(int orderId)
{
    var order = _orderService.ShipOrder(orderId); // logic lives in service
    return View(order);
}

// ❌ BAD - dynamic ViewBag breaks at runtime if the property name is wrong
ViewBag.OrderTotal = 199.99m;
// In Razor: @ViewBag.OrdrTotal -- typo, silently null at runtime

// ✅ GOOD - strongly-typed ViewModel catches errors at compile time
public IActionResult Summary(int orderId)
{
    var vm = new OrderSummaryViewModel
    {
        OrderId = orderId,
        Total = _orderService.GetTotal(orderId)
    };
    return View(vm);
}
// In Razor: @model OrderSummaryViewModel -> @Model.Total (compile-checked)

// ❌ BAD - partial rendered with no surrounding form, data never reaches the controller
// ProductDetail.cshtml
<partial name="_ReviewForm" model="Model.NewReview" />
// Result: no HTTP POST ever happens

// ✅ GOOD - partial lives inside a form that POSTs to the controller
// ProductDetail.cshtml
<form asp-action="SubmitReview" asp-controller="Product" method="post">
    <partial name="_ReviewForm" model="Model.NewReview" />
    <button type="submit">Submit</button>
</form>
