[HttpPost] public IActionResult Edit(OrderViewModel vm) { ... }

// ✅ Razor Pages approach - PageModel owns the page logic, less ceremony
// Pages/Orders/Edit.cshtml.cs
public class EditModel : PageModel
{
    [BindProperty] public OrderViewModel Order { get; set; }
    public void OnGet(int id) => Order = _orderService.Get(id);
    public IActionResult OnPost() => RedirectToPage("Index");
}

// ❌ BAD - returning ViewResult directly locks the action to one result type
public ViewResult SaveShipment(ShipmentViewModel vm)
{
    if (!ModelState.IsValid) return View(vm);
    // cannot return a redirect here - compile error
}

// ✅ GOOD - IActionResult allows branching to different result types
public IActionResult SaveShipment(ShipmentViewModel vm)
{
    if (!ModelState.IsValid) return View(vm);       // ViewResult on error
    _shipmentService.Dispatch(vm);
    return RedirectToAction(nameof(Index));         // redirect on success
}

// ❌ BAD - assuming the model bound correctly without checking ModelState
[HttpPost]
public IActionResult BookAppointment(AppointmentViewModel vm)
{
    _appointmentService.Book(vm.PatientId, vm.AppointmentDate); // vm may be null!
    return RedirectToAction("Confirmation");
}

// ✅ GOOD - check ModelState before trusting the model
[HttpPost]
public IActionResult BookAppointment(AppointmentViewModel vm)
{
    if (!ModelState.IsValid) return View(vm); // catches date parse failure
    _appointmentService.Book(vm.PatientId, vm.AppointmentDate);
    return RedirectToAction("Confirmation");
}
